pub struct BlockStateEntry {
    pub name: &'static str,
    pub properties: Vec<(&'static str, &'static str)>,
}

/// Look up a block state by its numeric ID.
pub fn state_to_block(state_id: u16) -> Option<BlockStateEntry> {
    if (state_id as usize) >= 29671 { return None; }
    let (name_idx, prop_arr_idx) = BLOCK_STATES[state_id as usize];
    let name = BLOCK_NAMES[name_idx as usize];
    let (prop_start, prop_len) = PROP_ARRAYS[prop_arr_idx as usize];
    let mut properties = Vec::with_capacity(prop_len as usize);
    for i in 0..prop_len as usize {
        let pair_idx = PROP_INDICES[prop_start as usize + i] as usize;
        properties.push(PROP_PAIRS[pair_idx]);
    }
    Some(BlockStateEntry { name, properties })
}

/// Look up a block state ID from name and properties.
pub fn block_to_state(name: &str, properties: &[(&str, &str)]) -> Option<u16> {
    for &(name_idx, min_state, max_state) in &BLOCK_RANGES {
        if BLOCK_NAMES[name_idx as usize] != name { continue; }
        for sid in min_state..=max_state {
            let entry = state_to_block(sid).unwrap();
            if entry.properties.len() != properties.len() { continue; }
            let mut matches = true;
            for (k, v) in properties {
                if !entry.properties.iter().any(|(ek, ev)| ek == k && ev == v) {
                    matches = false;
                    break;
                }
            }
            if matches { return Some(sid); }
        }
        return None;
    }
    None
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_air_is_zero() {
        let entry = state_to_block(0).unwrap();
        assert_eq!(entry.name, "minecraft:air");
        assert!(entry.properties.is_empty());
    }

    #[test]
    fn test_stone_is_one() {
        let entry = state_to_block(1).unwrap();
        assert_eq!(entry.name, "minecraft:stone");
        assert!(entry.properties.is_empty());
    }

    #[test]
    fn test_block_with_properties() {
        // oak_log axis=y is default state (137), axis=x is 136
        let entry = state_to_block(136).unwrap();
        assert_eq!(entry.name, "minecraft:oak_log");
        assert!(entry.properties.contains(&("axis", "x")));

        let entry = state_to_block(137).unwrap();
        assert_eq!(entry.name, "minecraft:oak_log");
        assert!(entry.properties.contains(&("axis", "y")));
    }

    #[test]
    fn test_reverse_lookup() {
        let sid = block_to_state("minecraft:stone", &[]).unwrap();
        assert_eq!(sid, 1);

        let sid = block_to_state("minecraft:oak_log", &[("axis", "x")]).unwrap();
        assert_eq!(sid, 136);
    }

    #[test]
    fn test_out_of_range() {
        assert!(state_to_block(65535).is_none());
    }
}
